mapper.select:
select id,title,status,create_time,is_top,like_count,favorite_count,view_count,recommend_level,cover_image
from article

    
        and title like concat('%',#{keyword},'%')
    
    
        and category_id = #{categoryId}
    
    
        and status = #{status}
    

order by coalesce(is_top, 0) desc, create_time desc

select * from article
where status = 0 AND (recommend_level != 0 OR recommend_level IS NULL)
order by (like_count+view_count) desc limit #{i}

SELECT a.id, a.title, a.create_time, a.like_count, a.favorite_count, a.view_count, a.cover_image FROM article a JOIN ( SELECT at.article_id, COUNT(*) as common_tag_count FROM article_tags at WHERE at.tags_id IN
#{tagId}
AND at.article_id != #{articleId} GROUP BY at.article_id ORDER BY common_tag_count DESC LIMIT #{limit} ) ranked ON a.id = ranked.article_id WHERE a.status = 0 ORDER BY ranked.common_tag_count DESC

SELECT id, title, create_time, like_count, favorite_count, view_count, cover_image
FROM article
WHERE id != #{articleId}
  AND category_id = #{categoryId}
  AND status = 0
ORDER BY create_time DESC
    LIMIT #{limit}
